import React from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { ResponsiveChartContainer, BarPlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface RideSummary {
  distance: number;
  averageSpeed: number;
  elevationGain: number;
}

interface PowerZone {
  zone: string;
  duration: number;
}

interface CyclingStatsData {
  rideSummary: RideSummary;
  powerZones: PowerZone[];
}

export default function Widget() {
  const cyclingData = response.data as CyclingStatsData;
  const { rideSummary, powerZones } = cyclingData;
  const clipPathId = `clip-path-${response.widget.id}`;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 450, bgcolor: '#2B2B2B' }} elevation={3}>
      <CardContent sx={{ p: 2 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: '#1B998B' }}>
              Ride Summary
            </Typography>
            <Typography variant="body2" sx={{ color: '#FFFFFF' }}>
              Distance: {rideSummary.distance} km
            </Typography>
            <Typography variant="body2" sx={{ color: '#FFFFFF' }}>
              Average Speed: {rideSummary.averageSpeed} km/h
            </Typography>
            <Typography variant="body2" sx={{ color: '#FFFFFF' }}>
              Elevation Gain: {rideSummary.elevationGain} m
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'bar',
                  data: powerZones.map((zone) => zone.duration),
                  color: '#ED217C',
                },
              ]}
              xAxis={[
                {
                  scaleType: 'band',
                  data: powerZones.map((zone) => zone.zone),
                  id: 'zones',
                },
              ]}
              yAxis={[{ id: 'duration' }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <BarPlot />
              </g>
              <ChartsXAxis
                axisId="zones"
                tickLabelStyle={{ fontSize: 11, fill: '#FFFFFF' }}
              />
              <ChartsYAxis
                axisId="duration"
                tickLabelStyle={{ fontSize: 11, fill: '#FFFFFF' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
